parameters.functionCode:
const att = items[0].binary?.attachment_0;
if (!att) return items;
const base64 = att.data;
const mime = att.mimeType || 'application/octet-stream';
const filename = att.fileName || 'invoice.pdf';
return [{ json: { base64, mime, filename, from: items[0].json.from, subject: items[0].json.subject } }];

